import type { Metadata } from "next";

interface Post {
  userId: number;
  id: number;
  title: string;
  body: string;
}

interface Comment {
  postId: number;
  id: number;
  name: string;
  email: string;
  body: string;
}

interface PageProps {
  params: Promise<{ id: string }>;
}

export async function generateStaticParams() {
  const posts: Post[] = await fetch(
    "https://jsonplaceholder.typicode.com/posts"
  ).then((res) => res.json());

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({
  params,
}: PageProps): Promise<Metadata> {
  const { id } = await params;
  const post: Post = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}`
  ).then((res) => res.json());

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPost({ params }: PageProps) {
  const { id } = await params;

  const [post, comments] = await Promise.all([
    fetch(`https://jsonplaceholder.typicode.com/posts/${id}`).then(
      (res) => {
        if (!res.ok) throw new Error("Post not found");
        return res.json() as Promise<Post>;
      }
    ),
    fetch(
      `https://jsonplaceholder.typicode.com/posts/${id}/comments`
    ).then((res) => res.json() as Promise<Comment[]>),
  ]);

  return (
    <>
      <article>
        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    </>
  );
}

import { NextRequest, NextResponse } from "next/server";

export async function GET() {
  const posts = [
    { id: 1, title: "First Post", content: "This is the first post" },
    { id: 2, title: "Second Post", content: "This is the second post" },
  ];

  return NextResponse.json(posts);
}

export async function POST(request: NextRequest) {
  const body = await request.json();
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json(
      { error: "Title and content are required" },
      { status: 400 }
    );
  }

  const newPost = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(newPost, { status: 201 });
}

import { NextRequest, NextResponse } from "next/server";

interface RouteParams {
  params: Promise<{ id: string }>;
}

export async function GET(_request: NextRequest, { params }: RouteParams) {
  const { id } = await params;

  const post = {
    id: parseInt(id),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: NextRequest, { params }: RouteParams) {
  const { id } = await params;
  const body = await request.json();
  const { title, content } = body;

  const updatedPost = {
    id: parseInt(id),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: NextRequest, { params }: RouteParams) {
  const { id } = await params;

  return NextResponse.json({
    message: `Post ${id} deleted successfully`,
  });
}

"use client";

import {
  createContext,
  useContext,
  useState,
  type ReactNode,
} from "react";

interface AppContextType {
  theme: string;
  setTheme: (theme: string) => void;
}

const AppContext = createContext<AppContextType | null>(null);

export function AppProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState("light");

  return (
    <AppContext.Provider value={{ theme, setTheme }}>
      {children}
    </AppContext.Provider>
  );
}

export function useAppContext() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error("useAppContext must be used within AppProvider");
  }
  return context;
}
